export default function ContractTable({ contracts }: any) {
  return (
    <div className="border p-4 overflow-x-auto">
      <table className="w-full text-sm">
        <thead>
          <tr className="bg-gray-100">
            <th>Seq</th>
            <th>contractId</th>
            <th>buyerId</th>
            <th>buyerUsername</th>
            <th>status</th>
            <th>delivery</th>
            <th>total</th>
          </tr>
        </thead>

        <tbody>
          {contracts?.map((c: any, i: number) => (
            <tr key={c.contractId} className="text-center">
              <td>{i + 1}</td>
              <td>{c.contractId}</td>
              <td>{c.buyerId}</td>
              <td>{c.buyerUsername}</td>
              <td>{c.contractStatus}</td>
              <td>{c.deliveryMethod}</td>
              <td>{c.totalAmount}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}